h Date<input class="form-control" type="date" name="birth_date" value="<?=ws_h($e['birth_date']??'')?>"></label><label>Gender<select class="form-select" name="gender"><option value="">Select</option><?php foreach(['male'=>'Male','female'=>'Female','other'=>'Other'] as $k=>$v):?><option value="<?=$k?>" <?=($e['gender']??'')===$k?'selected':''?>><?=$v?></option><?php endforeach;?></select></label><label>Civil Status<select class="form-select" name="civil_status"><option value="">Select</option><?php foreach(['single'=>'Single','married'=>'Married','widowed'=>'Widowed','separated'=>'Separated'] as $k=>$v):?><option value="<?=$k?>" <?=($e['civil_status']??'')===$k?'selected':''?>><?=$v?></option><?php endforeach;?></select></label><label>Phone<input class="form-control" name="phone" value="<?=ws_h($e['phone']??'')?>"></label><label>Email<input class="form-control" name="email" value="<?=ws_h($e['email']??'')?>"></label><label class="full">Address<textarea class="form-control" name="address" rows="2"><?=ws_h($e['address']??'')?></textarea></label><label>Emergency Contact<input class="form-control" name="emergency_contact" value="<?=ws_h($e['emergency_contact']??'')?>"></label><label>Emergency Phone<input class="form-control" name="emergency_phone" value="<?=ws_h($e['emergency_phone']??'')?>"></label></div></section><section><h6>Employment Details</h6><div class="mb-form-grid"><label>Department<select class="form-select" name="department_id"><option value="">Select Department</option><?php foreach($deps as $d):?><option value="<?= (int)$d['id']?>" data-category="<?=ws_h($d['category'])?>" <?=((int)($e['department_id']??0)===(int)$d['id']?'selected':'')?>><?=ws_h(ucfirst($d['category']).' · '.$d['name'])?></option><?php endforeach;?></select></label><label>Job Title<select class="form-select" name="job_title_id" data-job-title-select><option value="">Select Job Title</option><?php foreach($jobs as $j):?><option value="<?= (int)$j['id']?>" data-rate="<?=ws_h($j['salary_rate'])?>" data-rate-type="<?=ws_h($j['rate_type'])?>" data-category="<?=ws_h($j['category'])?>" data-department="<?= (int)$j['department_id']?>" <?=((int)($e['job_title_id']??0)===(int)$j['id']?'selected':'')?>><?=ws_h(ucfirst($j['category']).' · '.$j['title'].' · '.mb_money($j['salary_rate']).' / '.$j['rate_type'])?></option><?php endforeach;?></select></label><label>Manual Job Title<input class="form-control" name="job_title" value="<?=ws_h($e['job_title']??'')?>" placeholder="Optional override"></label><label>Employee Type<input class="form-control" name="employee_type" value="<?=ws_h($e['employee_type']??'')?>" placeholder="Regular, Contractual, Project-based"></label><label>Hire Date<input class="form-control" type="date" name="hire_date" value="<?=ws_h($e['hire_date']??'')?>"></label><label>Rate Type<select class="form-select" name="rate_type"><option value="daily" <?=($e['rate_type']??'daily')==='daily'?'selected':''?>>Daily</option><option value="monthly" <?=($e['rate_type']??'')==='monthly'?'selected':''?>>Monthly</option><option value="hourly" <?=($e['rate_type']??'')==='hourly'?'selected':''?>>Hourly</option></select></label><label>Salary Rate<input class="form-control" type="number" step="0.01" name="salary_rate" value="<?=ws_h($e['salary_rate']??($e['daily_rate']??0))?>"></label><label class="full">Notes<textarea class="form-control" name="notes" rows="3"><?=ws_h($e['notes']??'')?></textarea></label></div></section><section><h6>Required Documentation</h6><div class="employee-doc-grid"><?php foreach(ws_doc_labels() as $key=>$label): $existing=$docHave[$key]??null; ?><div class="doc-tile <?= $existing?'has-doc':''?>"><label class="form-check"><input class="form-check-input" type="checkbox" name="doc_required[]" value="<?=$key?>" <?= $existing?'checked':''?>> <span class="form-check-label"><?=$label?></span></label><?php if($existing):?><a class="small" target="_blank" href="<?=ws_h($existing['file_path'])?>">View uploaded file</a><?php endif;?><input class="form-control form-control-sm" type="file" name="doc_<?=$key?>" accept=".pdf,.jpg,.jpeg,.png,.webp,.doc,.docx"><select class="form-select form-select-sm" name="doc_status[<?=$key?>]"><option value="pending">Pending</option><option value="submitted" <?=($existing['status']??'')==='submitted'?'selected':''?>>Submitted</option><option value="verified" <?=($existing['status']??'')==='verified'?'selected':''?>>Verified</option><option value="expired" <?=($existing['status']??'')==='expired'?'selected':''?>>Expired</option></select></div><?php endforeach;?></div></section></main></div></div><div class="modal-footer"><button type="button" class="btn btn-outline-secondary" data-bs-dismiss="modal">Cancel</button><button class="btn btn-primary">Save Employee</button></div></form></div></div><?php }
function ws_render_employee_view(PDO $pdo,int $id): void { $e=ws_fetch_employee($pdo,$id); if(!$e){echo '<div class="alert alert-warning">Employee not found.</div>';return;} $docs=ws_employee_docs($pdo,$id); ?><div class="employee-view-print"><div class="d-flex justify-content-between align-items-start mb-3"><div class="d-flex align-items-start gap-3"><div class="employee-photo-preview employee-photo-preview-square small"><?php if(!empty($e['photo_path'])):?><img src="<?=ws_h($e['photo_path'])?>" alt="photo"><?php else:?><span>Photo</span><?php endif;?></div><div><h4 class="mb-1"><?=ws_h($e['full_name'])?></h4><div class="text-muted"><?=ws_h($e['employee_code'])?> · <?=ws_h(ucfirst($e['category']??''))?> · <?=ws_h($e['job_title_name'] ?: $e['job_title'])?></div><div><?=ws_h($e['department_name'])?> · <?=ws_money($e['salary_rate'] ?: $e['daily_rate'])?> / <?=ws_h($e['rate_type']??'daily')?></div></div></div><button class="btn btn-outline-secondary btn-sm" onclick="window.print()">Print</button></div><div class="row g-3"><div class="col-md-6"><div class="workspace-section-card"><h6>Personal</h6><p class="mb-1"><b>Phone:</b> <?=ws_h($e['phone'])?></p><p class="mb-1"><b>Email:</b> <?=ws_h($e['email'])?></p><p class="mb-1"><b>Birth Date:</b> <?=ws_h($e['birth_date'])?></p><p class="mb-1"><b>Address:</b> <?=nl2br(ws_h($e['address']))?></p></div></div><div class="col-md-6"><div class="workspace-section-card employee-id-card"><h6>Employee ID Preview</h6><div class="id-name"><?=ws_h($e['full_name'])?></div><div class="id-code"><?=ws_h($e['employee_code'])?></div><div><?=ws_h($e['job_title_name'] ?: $e['job_title'])?></div><div><?=ws_h(ucfirst($e['category']??''))?> Department</div></div></div></div><h6 class="mt-3">Documents</h6><div class="employee-doc-grid"><?php foreach(ws_doc_labels() as $k=>$label): $found=null; foreach($docs as $d){if($d['document_type']===$k){$found=$d;break;}} ?><div class="doc-tile <?= $found?'has-doc':''?>"><strong><?=$label?></strong><div class="small"><?= $found?ws_h($found['status']):'Missing'?></div><?php if($found && $found['file_path']):?><a target="_blank" href="<?=ws_h($found['file_path'])?>">Open file</a><?php endif;?></div><?php endforeach;?></div></div><?php }
function ws_render_employees(PDO $pdo,string $q=''): void { require_permission($pdo,'view_hr'); $can=current_user_can($pdo,'manage_employees'); $params=[];$where=''; if($q!==''){ $where="WHERE e.full_name LIKE ? OR e.employee_code LIKE ? OR e.phone LIKE ? OR jt.title LIKE ? OR d.name LIKE ?"; $params=array_fill(0,5,'%'.$q.'%'); } $st=$pdo->prepare("SELECT e.*,jt.title job_title_name,d.name department_name FROM mb_employees e LEFT JOIN mb_job_titles jt ON jt.id=e.job_title_id LEFT JOIN mb_departments d ON d.id=e.department_id $where ORDER BY e.category,e.full_name LIMIT 300"); $st->execute($params); $rows=$st->fetchAll(PDO::FETCH_ASSOC); $office=array_filter($rows,fn($r)=>($r['category']??'office')==='office'); $field=array_filter($rows,fn($r)=>($r['category']??'')==='field'); ?>
<div class="d-flex justify-content-between align-items-center mb-3"><div><h5 class="mb-0">Employees</h5><div class="text-muted small">Office and field records with resume profile, documents, salary title, attendance, payroll, and ID printing.</div></div><div class="d-flex gap-2"><?php if($can): ?><button class="btn btn-outline-primary btn-sm" data-module="departments">Departments</button><button class="btn btn-outline-primary btn-sm" data-module="job_titles">Job Titles</button><button class="btn btn-primary btn-sm" data-workspace-open="employeeResumeModal">New Employee</button><?php endif; ?></div></div>
<div class="row g-3 mb-3"><div class="col-md-3"><div class="workspace-stat"><div class="stat-kicker">Office</div><div class="stat-main"><?=count($office)?></div></div></div><div class="col-md-3"><div class="workspace-stat"><div class="stat-kicker">Field</div><div class="stat-main"><?=count($field)?></div></div></div><div class="col-md-3"><div class="workspace-stat"><div class="stat-kicker">Active</div><div class="stat-main"><?=count(array_filter($rows,fn($r)=>($r['status']??'')==='active'))?></div></div></div><div class="col-md-3"><div class="workspace-stat"><div class="stat-kicker">Missing Docs</div><div class="stat-main"><?php $missing=0; foreach($rows as $r){$c=$pdo->prepare('SELECT COUNT(*) FROM mb_employee_documents WHERE employee_id=?');$c->execute([$r['id']]); if((int)$c->fetchColumn()<3)$missing++;} echo $missing;?></div></div></div></div>
<ul class="nav nav-pills mb-3 employee-category-tabs"><li class="nav-item"><button class="nav-link active" data-emp-cat="office" type="button">Office Employees</button></li><li class="nav-item"><button class="nav-link" data-emp-cat="field" type="button">Field Workers</button></li></ul>
<?php foreach(['office'=>$office,'field'=>$field] as $cat=>$list): ?><div class="employee-cat-pane <?= $cat==='office'?'active':''?>" data-emp-pane="<?=$cat?>"><div class="table-responsive workspace-table-wrap"><table class="table table-hover workspace-table"><thead><tr><th>Employee</th><th>Job / Department</th><th>Rate</th><th>Status</th><th>Contact</th><th class="text-end">Actions</th></tr></thead><tbody><?php foreach($list as $r): ?><tr><td><div class="d-flex align-items-center gap-2"><div class="employee-thumb"><?php if(!empty($r['photo_path'])):?><img src="<?=ws_h($r['photo_path'])?>" alt="photo" style="width:42px;height:42px;max-width:42px;max-height:42px;min-width:42px;min-height:42px;display:block;object-fit:cover;object-position:center;"><?php endif;?></div><div><strong><?=ws_h($r['full_name'])?></strong><div class="text-muted small"><?=ws_h($r['employee_code'])?></div></div></div></td><td><?=ws_h($r['job_title_name'] ?: $r['job_title'])?><div class="text-muted small"><?=ws_h($r['department_name'] ?: $r['department'])?></div></td><td><?=ws_money($r['salary_rate'] ?: $r['daily_rate'])?><div class="text-muted small"><?=ws_h($r['rate_type']??'daily')?></div></td><td><span class="badge text-bg-light border"><?=ws_h($r['status'])?></span></td><td><?=ws_h($r['phone'])?><div class="text-muted small"><?=ws_h($r['email'])?></div></td><td class="text-end"><button class="btn btn-sm btn-outline-secondary" data-ws-view="employees" data-id="<?= (int)$r['id']?>">View</button> <?php if($can): ?><button class="btn btn-sm btn-outline-primary" data-ws-edit="employees" data-id="<?= (int)$r['id']?>">Edit</button> <button class="btn btn-sm btn-outline-danger" data-confirm-action="Delete employee?" data-id="<?= (int)$r['id']?>">Delete</button><?php endif;?></td></tr><?php endforeach; if(!$list): ?><tr><td colspan="6" class="text-center text-muted py-4">No <?=ws_h($cat)?> employees yet.</td></tr><?php endif;?></tbody></table></div></div><?php endforeach; ?><?php if($can) ws_render_employee_modal($pdo); }

function ws_render_attendance(PDO $pdo,string $q=''): void { require_permission($pdo,'view_hr'); $can=current_user_can($pdo,'manage_attendance'); $date=$_GET['date'] ?? date('Y-m-d'); if(!preg_match('/^\d{4}-\d{2}-\d{2}$/',$date)) $date=date('Y-m-d'); $settings=$pdo->query("SELECT * FROM mb_attendance_settings WHERE id=1")->fetch(PDO::FETCH_ASSOC); $emps=$pdo->query("SELECT id,employee_code,full_name,category,salary_rate,daily_rate FROM mb_employees WHERE status IN ('active','probationary') ORDER BY category,full_name")->fetchAll(PDO::FETCH_ASSOC); $att=[]; $s=$pdo->prepare("SELECT * FROM mb_attendance WHERE attendance_date=?"); $s->execute([$date]); foreach($s->fetchAll(PDO::FETCH_ASSOC) as $a){$att[$a['employee_id']]=$a;} $month=substr($date,0,7); $first=new DateTime($month.'-01'); $days=(int)$first->format('t'); $startDow=(int)$first->format('w'); $counts=[]; $s=$pdo->prepare("SELECT attendance_date,status,COUNT(*) c FROM mb_attendance WHERE attendance_date BETWEEN ? AND ? GROUP BY attendance_date,status"); $s->execute([$month.'-01',$month.'-'.$days]); foreach($s as $r){$counts[$r['attendance_date']][$r['status']]=$r['c'];} ?>
<div class="d-flex justify-content-between align-items-center mb-3"><div><h5 class="mb-0">Attendance Control</h5><div class="text-muted small">Calendar checking with configurable late, present, absent, and overtime rules.</div></div><button class="btn btn-outline-primary btn-sm" data-workspace-open="attendanceSettingsModal">Settings</button></div>
<div class="attendance-layout"><div class="workspace-section-card"><div class="d-flex justify-content-between align-items-center mb-2"><strong><?=date('F Y',strtotime($date))?></strong><input class="form-control form-control-sm" style="max-width:160px" type="date" value="<?=ws_h($date)?>" data-attendance-date></div><div class="attendance-calendar"><?php foreach(['Sun','Mon','Tue','Wed','Thu','Fri','Sat'] as $d):?><div class="cal-head"><?=$d?></div><?php endforeach; for($i=0;$i<$startDow;$i++) echo '<div class="cal-cell muted"></div>'; for($d=1;$d<=$days;$d++): $dt=$month.'-'.str_pad((string)$d,2,'0',STR_PAD_LEFT); $c=$counts[$dt]??[]; ?><button type="button" class="cal-cell <?= $dt===$date?'active':''?>" data-att-date="<?=$dt?>"><b><?=$d?></b><small>P <?= (int)($c['present']??0)?> · L <?= (int)($c['late']??0)?> · A <?= (int)($c['absent']??0)?></small></button><?php endfor;?></div></div><div class="workspace-section-card attendance-sheet"><form data-spa-form><input type="hidden" name="module" value="attendance"><input type="hidden" name="action" value="bulk_save"><input type="hidden" name="attendance_date" value="<?=ws_h($date)?>"><div class="d-flex justify-content-between mb-2"><strong>Daily Sheet · <?=date('M d, Y',strtotime($date))?></strong><span class="small text-muted">Start <?=$settings['work_start']?> · Grace <?=$settings['late_grace_minutes']?> min · OT after <?=$settings['overtime_after_hours']?> hrs</span></div><div class="table-responsive"><table class="table table-sm align-middle workspace-table"><thead><tr><th>Employee</th><th>Status</th><th>Time In</th><th>Time Out</th><th>Late Min</th><th>OT Hrs</th><th>Notes</th></tr></thead><tbody><?php foreach($emps as $e): $a=$att[$e['id']]??[]; ?><tr><td><strong><?=ws_h($e['full_name'])?></strong><div class="text-muted small"><?=ws_h(ucfirst($e['category']))?> · <?=ws_h($e['employee_code'])?></div><input type="hidden" name="rows[<?= (int)$e['id']?>][employee_id]" value="<?= (int)$e['id']?>"></td><td><select class="form-select form-select-sm" name="rows[<?= (int)$e['id']?>][status]"><?php foreach(['present'=>'Present','late'=>'Late','absent'=>'Absent','half_day'=>'Half Day','leave'=>'Leave','rest_day'=>'Rest Day'] as $k=>$v):?><option value="<?=$k?>" <?=($a['status']??'present')===$k?'selected':''?>><?=$v?></option><?php endforeach;?></select></td><td><input class="form-control form-control-sm" type="time" name="rows[<?= (int)$e['id']?>][time_in]" value="<?=ws_h($a['time_in']??'')?>"></td><td><input class="form-control form-control-sm" type="time" name="rows[<?= (int)$e['id']?>][time_out]" value="<?=ws_h($a['time_out']??'')?>"></td><td><input class="form-control form-control-sm" type="number" name="rows[<?= (int)$e['id']?>][late_minutes]" value="<?=ws_h($a['late_minutes']??0)?>"></td><td><input class="form-control form-control-sm" type="number" step="0.01" name="rows[<?= (int)$e['id']?>][overtime_hours]" value="<?=ws_h($a['overtime_hours']??0)?>"></td><td><input class="form-control form-control-sm" name="rows[<?= (int)$e['id']?>][notes]" value="<?=ws_h($a['notes']??'')?>"></td></tr><?php endforeach;?></tbody></table></div><?php if($can): ?><button class="btn btn-primary btn-sm">Save Attendance</button><?php endif;?></form></div></div>
<div class="modal fade" id="attendanceSettingsModal"><div class="modal-dialog"><form class="modal-content" data-spa-form><input type="hidden" name="module" value="attendance"><input type="hidden" name="action" value="settings"><div class="modal-header"><h5 class="modal-title">Attendance Settings</h5><button class="btn-close" type="button" data-bs-dismiss="modal"></button></div><div class="modal-body"><div class="mb-form-grid single"><label>Work Start<input class="form-control" type="time" name="work_start" value="<?=substr($settings['work_start'],0,5)?>"></label><label>Work End<input class="form-control" type="time" name="work_end" value="<?=substr($settings['work_end'],0,5)?>"></label><label>Late Grace Minutes<input class="form-control" type="number" name="late_grace_minutes" value="<?=ws_h($settings['late_grace_minutes'])?>"></label><label>Overtime After Hours<input class="form-control" type="number" step="0.01" name="overtime_after_hours" value="<?=ws_h($settings['overtime_after_hours'])?>"></label><label>Overtime Multiplier<input class="form-control" type="number" step="0.01" name="overtime_rate_multiplier" value="<?=ws_h($settings['overtime_rate_multiplier'])?>"></label></div></div><div class="modal-footer"><button class="btn btn-primary">Save Settings</button></div></form></div></div><?php }
function ws_render_payroll(PDO $pdo,string $q=''): void { require_permission($pdo,'view_hr'); $start=$_GET['start'] ?? date('Y-m-01'); $end=$_GET['end'] ?? date('Y-m-t'); $items=ws_payroll_preview($pdo,$start,$end); $total=array_sum(array_column($items,'gross_pay')); $periods=$pdo->query("SELECT * FROM mb_payroll_periods ORDER BY period_end DESC,id DESC LIMIT 20")->fetchAll(PDO::FETCH_ASSOC); ?><div class="d-flex justify-content-between align-items-center mb-3"><div><h5 class="mb-0">Payroll</h5><div class="text-muted small">Computed from attendance status, late/absent counts, overtime hours, and employee salary rates.</div></div></div><div class="workspace-section-card mb-3"><form class="d-flex flex-wrap gap-2 align-items-end" data-payroll-filter><label class="small">Start<input class="form-control form-control-sm" type="date" name="start" value="<?=ws_h($start)?>"></label><label class="small">End<input class="form-control form-control-sm" type="date" name="end" value="<?=ws_h($end)?>"></label><button class="btn btn-outline-primary btn-sm" type="submit">Preview</button></form></div><div class="workspace-section-card"><div class="d-flex justify-content-between mb-2"><strong>Payroll Preview</strong><strong><?=ws_money($total)?></strong></div><div class="table-responsive"><table class="table table-sm workspace-table"><thead><tr><th>Employee</th><th>Rate</th><th>Present</th><th>Late</th><th>Absent</th><th>OT Hrs</th><th>Gross Pay</th></tr></thead><tbody><?php foreach($items as $i):?><tr><td><strong><?=ws_h($i['full_name'])?></strong><div class="text-muted small"><?=ws_h($i['employee_code'])?></div></td><td><?=ws_money($i['base_rate'])?></td><td><?=$i['present_days']?></td><td><?=$i['late_days']?></td><td><?=$i['absent_days']?></td><td><?=$i['overtime_hours']?></td><td><strong><?=ws_money($i['gross_pay'])?></strong></td></tr><?php endforeach;?></tbody></table></div><form data-spa-form><input type="hidden" name="module" value="payroll"><input type="hidden" name="action" value="save_period"><input type="hidden" name="period_start" value="<?=ws_h($start)?>"><input type="hidden" name="period_end" value="<?=ws_h($end)?>"><button class="btn btn-primary btn-sm">Save Payroll Period</button></form></div><h6 class="mt-4">Saved Payroll Periods</h6><div class="table-responsive workspace-table-wrap"><table class="table table-sm workspace-table"><thead><tr><th>Period</th><th>Status</th><th>Gross Pay</th><th>Created</th><th></th></tr></thead><tbody><?php foreach($periods as $p):?><tr><td><?=ws_h($p['period_start'])?> to <?=ws_h($p['period_end'])?></td><td><?=ws_h($p['status'])?></td><td><?=ws_money($p['gross_pay'])?></td><td><?=ws_h($p['created_at'])?></td><td class="text-end"><button class="btn btn-sm btn-outline-danger" data-confirm-action="Delete payroll period?" data-id="<?= (int)$p['id']?>">Delete</button></td></tr><?php endforeach;?></tbody></table></div><?php }
function ws_payroll_preview(PDO $pdo,string $start,string $end): array { $settings=$pdo->query("SELECT * FROM mb_attendance_settings WHERE id=1")->fetch(PDO::FETCH_ASSOC); $emps=$pdo->query("SELECT * FROM mb_employees WHERE status IN ('active','probationary') ORDER BY full_name")->fetchAll(PDO::FETCH_ASSOC); $out=[]; foreach($emps as $e){ $s=$pdo->prepare("SELECT status,COUNT(*) c,COALESCE(SUM(overtime_hours),0) ot FROM mb_attendance WHERE employee_id=? AND attendance_date BETWEEN ? AND ? GROUP BY status"); $s->execute([$e['id'],$start,$end]); $present=$late=$absent=$ot=0; foreach($s as $r){ if(in_array($r['status'],['present','late'],true)) $present+=(int)$r['c']; if($r['status']==='half_day') $present+=(int)$r['c']*0.5; if($r['status']==='late') $late+=(int)$r['c']; if($r['status']==='absent') $absent+=(int)$r['c']; $ot+=(float)$r['ot']; } $rate=(float)($e['salary_rate'] ?: $e['daily_rate']); $gross=($present*$rate)+($ot*($rate/8)*(float)($settings['overtime_rate_multiplier']??1.25)); $out[]=['employee_id'=>$e['id'],'employee_code'=>$e['employee_code'],'full_name'=>$e['full_name'],'base_rate'=>$rate,'present_days'=>$present,'late_days'=>$late,'absent_days'=>$absent,'overtime_hours'=>$ot,'gross_pay'=>$gross]; } return $out; }

function ws_save_job_title(PDO $pdo): void { require_permission($pdo,'manage_employees'); $id=(int)($_POST['id']??0); $data=[trim($_POST['title']??''),($_POST['department_id']?:null),trim($_POST['category']??'office'),trim($_POST['rate_type']??'daily'),ws_num($_POST['salary_rate']??0),trim($_POST['description']??''),trim($_POST['status']??'active')]; if($id>0) $pdo->prepare("UPDATE mb_job_titles SET title=?,department_id=?,category=?,rate_type=?,salary_rate=?,description=?,status=? WHERE id=?")->execute([...$data,$id]); else $pdo->prepare("INSERT INTO mb_job_titles (title,department_id,category,rate_type,salary_rate,description,status) VALUES (?,?,?,?,?,?,?)")->execute($data); ws_json(['ok'=>true,'message'=>'Job title saved.']); }
function ws_save_department(PDO $pdo): void { require_permission($pdo,'manage_employees'); $id=(int)($_POST['id']??0); $data=[trim($_POST['name']??''),trim($_POST['category']??'office'),trim($_POST['manager_name']??''),trim($_POST['description']??''),trim($_POST['status']??'active')]; if($id>0) $pdo->prepare("UPDATE mb_departments SET name=?,category=?,manager_name=?,description=?,status=? WHERE id=?")->execute([...$data,$id]); else $pdo->prepare("INSERT INTO mb_departments (name,category,manager_name,description,status) VALUES (?,?,?,?,?)")->execute($data); ws_json(['ok'=>true,'message'=>'Department saved.']); }
function ws_save_employee(PDO $pdo): void { require_permission($pdo,'manage_employees'); $id=(int)($_POST['id']??0); $code=trim($_POST['employee_code']??'') ?: ('EMP-'.date('Ymd-His')); $jobId=(int)($_POST['job_title_id']??0); $job=$jobId?($pdo->query("SELECT * FROM mb_job_titles WHERE id=".$jobId)->fetch(PDO::FETCH_ASSOC) ?: null):null; $rate=ws_num($_POST['salary_rate']??0); if($rate<=0 && $job) $rate=(float)$job['salary_rate']; $rateType=trim($_POST['rate_type']??($job['rate_type']??'daily')); $photo=ws_upload_file('photo','employees/photos'); $fields=['employee_code','full_name','employee_type','job_title','department','phone','email','daily_rate','status','notes','photo_path','birth_date','gender','civil_status','address','emergency_contact','emergency_phone','category','job_title_id','department_id','hire_date','salary_rate','rate_type']; $data=[$code,trim($_POST['full_name']??''),trim($_POST['employee_type']??''),trim($_POST['job_title']??($job['title']??'')), '', trim($_POST['phone']??''),trim($_POST['email']??''),$rate,trim($_POST['status']??'active'),trim($_POST['notes']??''),$photo,($_POST['birth_date']?:null),trim($_POST['gender']??''),trim($_POST['civil_status']??''),trim($_POST['address']??''),trim($_POST['emergency_contact']??''),trim($_POST['emergency_phone']??''),trim($_POST['category']??($job['category']??'office')),($jobId?:null),($_POST['department_id']?:null),($_POST['hire_date']?:null),$rate,$rateType]; if($id>0){ if(!$photo){$fields=array_values(array_filter($fields,fn($f)=>$f!=='photo_path')); array_splice($data,10,1);} $sets=implode(',',array_map(fn($f)=>"`$f`=?",$fields)); $pdo->prepare("UPDATE mb_employees SET $sets WHERE id=?")->execute([...$data,$id]); } else { $cols=implode(',',array_map(fn($f)=>"`$f`",$fields)); $qs=implode(',',array_fill(0,count($fields),'?')); $pdo->prepare("INSERT INTO mb_employees ($cols) VALUES ($qs)")->execute($data); $id=(int)$pdo->lastInsertId(); }
  foreach(ws_doc_labels() as $key=>$label){ $path=ws_upload_file('doc_'.$key,'employees/docs'); $status=$_POST['doc_status'][$key] ?? 'pending'; if($path || in_array($key,$_POST['doc_required']??[],true)){ $exists=$pdo->prepare("SELECT id FROM mb_employee_documents WHERE employee_id=? AND document_type=? ORDER BY id DESC LIMIT 1"); $exists->execute([$id,$key]); $docId=(int)$exists->fetchColumn(); if($docId){ if($path) $pdo->prepare("UPDATE mb_employee_documents SET file_path=?,status=?,document_title=? WHERE id=?")->execute([$path,$status,$label,$docId]); else $pdo->prepare("UPDATE mb_employee_documents SET status=?,document_title=? WHERE id=?")->execute([$status,$label,$docId]); } else $pdo->prepare("INSERT INTO mb_employee_documents (employee_id,document_type,document_title,file_path,status) VALUES (?,?,?,?,?)")->execute([$id,$key,$label,$path,$status]); } }
  ws_json(['ok'=>true,'message'=>'Employee resume saved.']); }
function ws_save_attendance_bulk(PDO $pdo): void { require_permission($pdo,'manage_attendance'); $date=$_POST['attendance_date']??date('Y-m-d'); foreach(($_POST['rows']??[]) as $row){ $emp=(int)($row['employee_id']??0); if(!$emp) continue; $status=trim($row['status']??'present'); $payable=['present'=>1,'late'=>1,'half_day'=>0.5,'leave'=>1,'rest_day'=>0,'absent'=>0][$status] ?? 1; $pdo->prepare("INSERT INTO mb_attendance (employee_id,attendance_date,time_in,time_out,status,late_minutes,overtime_hours,payable_day,notes,created_by) VALUES (?,?,?,?,?,?,?,?,?,?) ON DUPLICATE KEY UPDATE time_in=VALUES(time_in),time_out=VALUES(time_out),status=VALUES(status),late_minutes=VALUES(late_minutes),overtime_hours=VALUES(overtime_hours),payable_day=VALUES(payable_day),notes=VALUES(notes)")->execute([$emp,$date,($row['time_in']?:null),($row['time_out']?:null),$status,(int)($row['late_minutes']??0),ws_num($row['overtime_hours']??0),$payable,trim($row['notes']??''),(int)$_SESSION['user_id']]); } ws_json(['ok'=>true,'message'=>'Attendance saved.']); }
function ws_save_attendance_settings(PDO $pdo): void { require_permission($pdo,'manage_attendance'); $pdo->prepare("UPDATE mb_attendance_settings SET work_start=?,work_end=?,late_grace_minutes=?,overtime_after_hours=?,overtime_rate_multiplier=? WHERE id=1")->execute([($_POST['work_start']??'08:00'),($_POST['work_end']??'17:00'),(int)($_POST['late_grace_minutes']??15),ws_num($_POST['overtime_after_hours']??8),ws_num($_POST['overtime_rate_multiplier']??1.25)]); ws_json(['ok'=>true,'message'=>'Attendance settings saved.']); }
function ws_save_payroll_period(PDO $pdo): void { require_permission($pdo,'manage_employees'); $start=$_POST['period_start']??date('Y-m-01'); $end=$_POST['period_end']??date('Y-m-t'); $items=ws_payroll_preview($pdo,$start,$end); $total=array_sum(array_column($items,'gross_pay')); $pdo->prepare("INSERT INTO mb_payroll_periods (period_start,period_end,title,status,gross_pay,created_by) VALUES (?,?,?,'draft',?,?)")->execute([$start,$end,'Payroll '.$start.' to '.$end,$total,(int)$_SESSION['user_id']]); $pid=(int)$pdo->lastInsertId(); foreach($items as $i){ $pdo->prepare("INSERT INTO mb_payroll_items (payroll_id,employee_id,base_rate,present_days,late_days,absent_days,overtime_hours,gross_pay) VALUES (?,?,?,?,?,?,?,?)")->execute([$pid,$i['employee_id'],$i['base_rate'],$i['present_days'],$i['late_days'],$i['absent_days'],$i['overtime_hours'],$i['gross_pay']]); } ws_json(['ok'=>true,'message'=>'Payroll period saved.']); }

function ws_save_generic(PDO $pdo, string $module): void { $map=['expenses'=>['manage_expenses','mb_expenses',['expense_date','category','vendor','description','amount','tax_amount','reference_no','status']], 'invoices'=>['manage_invoices','mb_invoices',['invoice_no','client_name','issue_date','due_date','amount','paid_amount','status','notes']], 'employees'=>['manage_employees','mb_employees',['employee_code','full_name','employee_type','job_title','department','phone','email','daily_rate','status','notes']], 'attendance'=>['manage_attendance','mb_attendance',['employee_id','attendance_date','time_in','time_out','status','notes']], 'inventory'=>['manage_inventory','mb_inventory_items',['sku','item_name','category','unit','quantity','min_quantity','unit_cost','location','status','notes']], 'documents'=>['manage_documents','mb_documents',['title','category','status','file_path','expiry_date','notes']], 'plans'=>['manage_plans','mb_plan_files',['title','plan_type','revision','status','file_path','notes']]]; if(!isset($map[$module])) ws_json(['ok'=>false,'message'=>'Unsupported module'],400); [$perm,$table,$fields]=$map[$module]; require_permission($pdo,$perm); $id=(int)($_POST['id']??0); $vals=[]; foreach($fields as $f){ $vals[]=$_POST[$f] ?? null; } if($id>0){ $sets=implode(',',array_map(fn($f)=>"`$f`=?",$fields)); $pdo->prepare("UPDATE `$table` SET $sets WHERE id=?")->execute([...$vals,$id]); } else { $cols=implode(',',array_map(fn($f)=>"`$f`",$fields)); $qs=implode(',',array_fill(0,count($fields),'?')); $pdo->prepare("INSERT INTO `$table` ($cols,created_by) VALUES ($qs,?)")->execute([...$vals,(int)$_SESSION['user_id']]); } ws_json(['ok'=>true,'message'=>'Record saved.']); }
function ws_delete(PDO $pdo, string $module): void { $map=['projects'=>['manage_projects','mb_projects'],'estimates'=>['manage_estimates','mb_estimates'],'proposals'=>['manage_proposals','mb_proposals'],'expenses'=>['manage_expenses','mb_expenses'],'invoices'=>['manage_invoices','mb_invoices'],'employees'=>['manage_employees','mb_employees'],'attendance'=>['manage_attendance','mb_attendance'],'inventory'=>['manage_inventory','mb_inventory_items'],'documents'=>['manage_documents','mb_documents'],'plans'=>['manage_plans','mb_plan_files'],'job_titles'=>['manage_employees','mb_job_titles'],'departments'=>['manage_employees','mb_departments'],'payroll'=>['manage_employees','mb_payroll_periods']]; if(!isset($map[$module])) ws_json(['ok'=>false,'message'=>'Unsupported delete.'],400); [$perm,$table]=$map[$module]; require_permission($pdo,$perm); $pdo->prepare("DELETE FROM `$table` WHERE id=?")->execute([(int)($_POST['id']??0)]); ws_json(['ok'=>true,'message'=>'Deleted.']); }

try {
  if($_SERVER['REQUEST_METHOD']==='POST') { csrf_verify(); $module=$_POST['module']??''; $action=$_POST['action']??''; if($action==='delete') ws_delete($pdo,$module); if($module==='estimates' && $action==='save') ws_save_estimate($pdo); if($module==='projects' && $action==='save') ws_save_project($pdo); if($module==='proposals' && $action==='save') ws_save_proposal($pdo); if($module==='proposals' && $action==='approve') ws_approve_proposal($pdo); if($module==='job_titles' && $action==='save') ws_save_job_title($pdo); if($module==='departments' && $action==='save') ws_save_department($pdo); if($module==='employees' && $action==='save') ws_save_employee($pdo); if($module==='attendance' && $action==='bulk_save') ws_save_attendance_bulk($pdo); if($module==='attendance' && $action==='settings') ws_save_attendance_settings($pdo); if($module==='payroll' && $action==='save_period') ws_save_payroll_period($pdo); ws_save_generic($pdo,$module); }
  $module=$_GET['module'] ?? 'overview'; $mode=$_GET['mode'] ?? 'list'; $id=(int)($_GET['id'] ?? 0); $q=trim($_GET['q'] ?? '');
  if($mode==='view'){ if($module==='estimates') ws_render_estimate_view($pdo,$id); elseif($module==='projects') ws_render_project_view($pdo,$id); elseif($module==='proposals') ws_render_proposal_view($pdo,$id); elseif($module==='employees') ws_render_employee_view($pdo,$id); else echo '<div class="alert alert-info">View modal is available for main contractor modules.</div>'; exit; }
  if($mode==='edit'){ if($module==='estimates') ws_render_estimate_modal($pdo,ws_fetch_estimate($pdo,$id)); elseif($module==='projects'){ $s=$pdo->prepare("SELECT * FROM mb_projects WHERE id=?"); $s->execute([$id]); ws_render_project_modal($pdo,$s->fetch(PDO::FETCH_ASSOC) ?: []); } elseif($module==='proposals'){ $s=$pdo->prepare("SELECT * FROM mb_proposals WHERE id=?"); $s->execute([$id]); ws_render_proposal_modal($pdo,$s->fetch(PDO::FETCH_ASSOC) ?: []); } elseif($module==='employees') ws_render_employee_modal($pdo,ws_fetch_employee($pdo,$id)); elseif($module==='job_titles'){ $s=$pdo->prepare("SELECT * FROM mb_job_titles WHERE id=?"); $s->execute([$id]); ws_render_jobtitle_modal($pdo,$s->fetch(PDO::FETCH_ASSOC) ?: []); } elseif($module==='departments'){ $s=$pdo->prepare("SELECT * FROM mb_departments WHERE id=?"); $s->execute([$id]); ws_render_department_modal($pdo,$s->fetch(PDO::FETCH_ASSOC) ?: []); } else echo '<div class="alert alert-warning">Edit modal not available.</div>'; exit; }
  if($module==='overview') ws_render_overview($pdo); elseif($module==='estimates') ws_render_estimates($pdo,$q); elseif($module==='projects') ws_render_projects($pdo,$q); elseif($module==='proposals') ws_render_proposals($pdo,$q); elseif($module==='employees') ws_render_employees($pdo,$q); elseif($module==='attendance') ws_render_attendance($pdo,$q); elseif($module==='payroll') ws_render_payroll($pdo,$q); elseif($module==='job_titles') ws_render_jobtitles($pdo,$q); elseif($module==='departments') ws_render_departments($pdo,$q); elseif($module==='reports') { require_permission($pdo,'view_reports'); ws_render_overview($pdo); } else ws_render_generic($pdo,$module,$q);
} catch(Throwable $e) { if($_SERVER['REQUEST_METHOD']==='POST') ws_json(['ok'=>false,'message'=>$e->getMessage()],500); http_response_code(500); echo '<div class="alert alert-danger">'.ws_h($e->getMessage()).'</div>'; }
